    primary: "bg-slate-900 text-white hover:bg-slate-800 shadow-lg shadow-slate-900/20",
    secondary: "bg-amber-600 text-white hover:bg-amber-700 shadow-lg shadow-amber-600/20",
    outline: "border-2 border-slate-200 text-slate-700 hover:border-slate-900 hover:text-slate-900",
    ghost: "text-slate-600 hover:bg-slate-100",
    white: "bg-white text-slate-900 hover:bg-slate-50",
    ai: "bg-gradient-to-r from-indigo-600 to-purple-600 text-white hover:from-indigo-700 hover:to-purple-700 shadow-lg shadow-indigo-500/20"
  };
  return (
    <button type={type} onClick={onClick} className={`${baseStyle} ${variants[variant]} ${className}`} disabled={disabled}>
