// ---- Global AI Chat Component ---- //
const AcrelyAIChat = memo(({ properties, agents }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { role: 'assistant', text: "Hello! I'm Acrely AI, your real estate expert. I can help you find homes, analyze market trends, or connect with top agents. What's on your mind?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input;
    setInput("");
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    const systemInstruction = `
      You are Acrely Prime AI, the world's most advanced real estate concierge. 

      YOUR CAPABILITIES:
      1. ACCESS TO INTERNAL DATA: You know everything about the properties listed below.
      2. REAL-TIME WEB SEARCH: You MUST use Google Search to find current interest rates in India, neighborhood news, and competitor pricing trends.
      3. INVESTMENT ANALYST: Don't just list homes. Analyze them. Calculate potential rental yields based on current market rates you find online.

      INTERNAL DATA (Prioritize this for specific listings):
      Properties: ${JSON.stringify(properties?.map(p => ({ title: p.title, location: p.location, price: p.priceDisplay, type: p.type })) || [])}
      Agents: ${JSON.stringify(agents?.map(a => ({ name: a.name, role: a.role, location: a.location })) || [])}

      TONE:
      Sophisticated, Professional, Insightful, and Helpful. Like a high-end wealth manager.

      RULES:
      - If asked about something specific to a location (e.g., "Is Whitefield good?"), SEARCH for the latest infrastructure projects there.
      - Always cite your sources if you use Google Search.
      - Keep answers concise (under 3 paragraphs).
    `;

    const result = await callGemini(userMessage, systemInstruction);

    setMessages(prev => [...prev, { role: 'assistant', text: result.text, sources: result.sources }]);
    setIsLoading(false);
  };

  return (
    <>
      {/* Floating Button */}
       <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-[100] p-4 rounded-2xl shadow-2xl transition-all duration-300 hover:scale-105 flex items-center gap-2 group ${isOpen ? 'bg-slate-900 text-amber-500 ring-2 ring-amber-500/50' : 'bg-slate-900 text-white border border-white/10'}`}
      >
        {isOpen ? (
            <X className="w-6 h-6" />
        ) : (
            <>
                <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-amber-400 to-amber-600 flex items-center justify-center shadow-lg shadow-amber-500/30">
                     <Bot className="w-5 h-5 text-slate-900" />
                </div>
                <span className="font-bold pr-2">Ask AI</span>
            </>
        )}
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="fixed bottom-0 right-0 md:bottom-24 md:right-6 w-full md:w-[400px] h-[100vh] md:h-[650px] bg-slate-900/95 backdrop-blur-md md:rounded-3xl shadow-2xl z-[100] flex flex-col overflow-hidden animate-fade-in border border-white/10 ring-1 ring-black/50">

          {/* Real Estate Background Texture */}
          <div className="absolute inset-0 z-0 opacity-20 pointer-events-none mix-blend-overlay" style={{
             backgroundImage: 'url("https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80&w=1000")',
             backgroundSize: 'cover',
             backgroundPosition: 'center'
          }}></div>

          {/* Gradient Overlay */}
          <div className="absolute inset-0 z-0 bg-gradient-to-b from-slate-900/80 via-slate-900/95 to-slate-900 pointer-events-none"></div>

          {/* Header */}
          <div className="relative z-10 bg-white/5 backdrop-blur-md p-5 flex items-center gap-4 border-b border-white/5">
            <div className="relative">
               <div className="w-12 h-12 rounded-2xl bg-gradient-to-tr from-amber-400 to-amber-600 flex items-center justify-center shadow-lg shadow-amber-500/20">
                 <Bot className="w-7 h-7 text-slate-900" />
               </div>
               <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-emerald-500 border-2 border-slate-900 rounded-full animate-pulse"></div>
            </div>
            <div>
              <h3 className="text-white font-bold text-lg tracking-tight">Acrely Intelligence</h3>
              <p className="text-slate-400 text-xs flex items-center gap-1">
                 Real Estate Expert • Online
              </p>
            </div>
            <button onClick={() => setIsOpen(false)} className="ml-auto text-slate-400 hover:text-white md:hidden">
              <ChevronDown />
            </button>
          </div>

          {/* Messages Area */}
          <div className="relative z-10 flex-1 overflow-y-auto p-4 space-y-6 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-gradient-to-br from-amber-500 to-amber-600 text-white rounded-br-none font-medium' 
                    : 'bg-white/10 backdrop-blur-md border border-white/10 text-slate-200 rounded-bl-none'
                }`}>
                  {msg.text}
                </div>
                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-2 flex flex-wrap gap-2 max-w-[85%]">
                    {msg.sources.slice(0, 2).map((source, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={source.web?.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-[10px] flex items-center gap-1 bg-slate-800/50 border border-slate-700 px-2 py-1 rounded-full text-amber-400 hover:bg-slate-800 transition-colors"
                      >
                        <Globe className="w-3 h-3" />
                        {source.web?.title?.slice(0, 20)}...
                      </a>
                    ))}
                  </div>
                )}
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white/5 border border-white/5 p-3 rounded-2xl rounded-bl-none flex items-center gap-2">
                  <Loader2 className="w-4 h-4 animate-spin text-amber-500" />
                  <span className="text-xs text-slate-400">Analyzing market data...</span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="relative z-10 p-4 bg-gradient-to-t from-slate-900 via-slate-900 to-transparent">
            <form onSubmit={handleSend} className="bg-slate-800/50 backdrop-blur-xl border border-white/10 rounded-2xl p-1.5 flex gap-2 ring-1 ring-white/5 focus-within:ring-amber-500/50 transition-all">
              <input 
                type="text" 
                placeholder="Ask about prices, trends, or listings..." 
                className="flex-1 bg-transparent border-none px-4 py-3 focus:outline-none text-slate-200 placeholder-slate-500 text-sm"
                value={input}
                onChange={(e) => setInput(e.target.value)}
              />
              <button 
                type="submit"
                disabled={isLoading || !input.trim()}
                className="bg-amber-500 text-slate-900 p-3 rounded-xl hover:bg-amber-400 disabled:opacity-50 transition-colors shadow-lg shadow-amber-500/20"
              >
                <Send className="w-5 h-5" />
              </button>
            </form>
          </div>
        </div>
      )}
    </>
  );
});

