            <span className="text-white font-bold text-lg">A</span>
          </div>
          <span className={`text-2xl font-bold tracking-tight ${mobileMenuOpen ? 'text-white' : textColor}`}>
            acrely<span className="text-amber-500">.</span>
          </span>
        </div>

        {/* Desktop Nav */}
        <div className={`hidden lg:flex items-center gap-8 ${navTextColor}`}>
          {navLinks.map((link) => (
            <button 
              key={link.id}
              onClick={() => setView(link.id)}
              className={`text-sm font-medium hover:text-amber-500 transition-colors ${view === link.id ? 'text-amber-500 font-bold' : ''}`}
            >
              {link.name}
            </button>
          ))}
        </div>

        {/* Auth Buttons (Desktop) */}
