          <button 
            onClick={() => setView('login')}
            className={`text-sm font-medium ${textColor} hover:opacity-80 transition-opacity`}
          >
            Log In
          </button>
          <Button 
            onClick={() => setView('signup')}
            variant={isDarkBg ? "white" : "primary"} 
            className="px-5 py-2 text-sm"
          >
            Sign Up
