        </div>

        {/* Mobile Menu Toggle Button */}
        <button 
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          className={`lg:hidden z-50 p-2 rounded-full hover:bg-white/20 transition-colors ${mobileMenuOpen ? 'text-white' : textColor}`}
        >
          {mobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Mobile Menu Overlay - FIXED BACKGROUND */}
      {mobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-40 flex flex-col pt-24 pb-6 px-6 overflow-y-auto">
          {/* Menu Items */}
          <div className="flex flex-col items-center gap-8 w-full">
            {navLinks.map((link) => (
              <button 
                key={link.id}
                onClick={() => { setView(link.id); setMobileMenuOpen(false); }}
                className="text-3xl font-medium text-white hover:text-amber-500 transition-colors"
              >
                {link.name}
              </button>
            ))}

            <div className="w-full h-px bg-slate-800 max-w-xs my-4"></div>

            {/* Auth Buttons (Mobile) */}
