// ---- Invest Section Component (Enhanced) ---- //
const InvestSection = memo(() => {
  const [amount, setAmount] = useState(10000000);
  const [years, setYears] = useState(5);
  const [aiReport, setAiReport] = useState("");
  const [loadingReport, setLoadingReport] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleGenerateReport = async () => {
    setLoadingReport(true);
    setAiReport(""); 

    const prompt = `Act as a senior financial advisor. I want to invest ₹${(amount/10000000).toFixed(2)} Cr in Indian Real Estate for ${years} years.
    Use Google Search to find current rental yields in Bangalore, Mumbai, and Hyderabad.
    Suggest a strategy (Commercial vs Residential, REITs vs Physical). 

    Format the response EXACTLY as follows using simple markdown:
    **Strategy: [Strategy Name]**
    [Brief explanation]

    **Investment Outlook**
    * **Strategy:** [Detail]
    * **Location Relevance:** [Detail]
    * **Potential ROI:** [ROI %]
    * **Advantage:** [Detail]

    Keep it professional, concise and under 120 words.`;

    const result = await callGemini(prompt);
    setAiReport(result.text);
    setLoadingReport(false);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(aiReport);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const formatText = (text) => {
    if (!text) return null;
    return text.split('\n').map((line, index) => {
      if (line.trim().startsWith('**') && line.trim().endsWith('**')) {
         return <h4 key={index} className="text-white font-bold text-lg mt-4 mb-2">{line.replace(/\*\*/g, '')}</h4>;
      }
      if (line.trim().startsWith('**')) {
         const parts = line.split('**');
         return (
            <p key={index} className="text-slate-300 text-sm leading-relaxed mb-2">
               <strong className="text-amber-400">{parts[1]}</strong> {parts[2]}
            </p>
         );
      }
      if (line.trim().startsWith('* ')) {
         const content = line.replace('* ', '');
         if (content.includes('**')) {
            const parts = content.split('**');
            return (
               <li key={index} className="flex items-start gap-2 text-sm text-slate-300 mb-2">
                  <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-emerald-400 shrink-0"></span>
                  <span><span className="text-white font-semibold">{parts[1]}</span> {parts[2]}</span>
               </li>
            );
         }
         return (
            <li key={index} className="flex items-start gap-2 text-sm text-slate-300 mb-2">
               <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-emerald-400 shrink-0"></span>
               <span>{content}</span>
            </li>
         );
      }
      if (line.trim() === '') return <br key={index} />;
      return <p key={index} className="text-slate-300 text-sm leading-relaxed mb-2">{line}</p>;
    });
  };

  return (
  <div className="pt-24 pb-20 bg-slate-900 text-white min-h-screen">
    <div className="container mx-auto px-4 md:px-6">
      <div className="text-center max-w-3xl mx-auto mb-16 animate-fade-in-up">
        <Badge className="bg-amber-500/20 text-amber-400 mb-4 border border-amber-500/40">Coming Soon</Badge>
        <h1 className="text-4xl md:text-6xl font-bold mb-6">Real Estate Fractional Ownership</h1>
        <p className="text-lg md:text-xl text-slate-400">Own a piece of premium commercial real estate with as little as ₹5 Lakhs. Earn monthly rental yields and benefit from capital appreciation.</p>
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start">
        <div className="bg-white/5 p-6 md:p-8 rounded-2xl border border-white/10 backdrop-blur-sm shadow-2xl">
          <div className="flex items-center justify-between mb-8"><h3 className="text-2xl font-bold">Projected ROI Calculator</h3><BarChart3 className="text-amber-500" /></div>
          <div className="space-y-8">
            {/* Investment Amount Slider */}
            <div>
              <div className="flex justify-between items-end mb-4">
                <label className="text-sm font-medium text-slate-400">Investment Amount</label>
                <div className="flex items-baseline gap-1">
                    <span className="text-3xl font-bold text-white tracking-tight">₹{(amount/100000).toFixed(0)}</span>
                    <span className="text-sm font-semibold text-amber-400 uppercase tracking-wide">Lakhs</span>
                </div>
              </div>
              <input type="range" min="500000" max="50000000" step="500000" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className="w-full accent-amber-500 h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer" />
            </div>

            {/* Holding Period Slider */}
             <div>
              <div className="flex justify-between items-end mb-4">
                <label className="text-sm font-medium text-slate-400">Holding Period</label>
                <div className="flex items-baseline gap-1">
                    <span className="text-3xl font-bold text-white tracking-tight">{years}</span>
                    <span className="text-sm font-semibold text-amber-400 uppercase tracking-wide">Years</span>
                </div>
              </div>
              <input type="range" min="1" max="10" value={years} onChange={(e) => setYears(Number(e.target.value))} className="w-full accent-amber-500 h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer" />
            </div>
            <Button variant="ai" className="w-full py-4 relative overflow-hidden group" onClick={handleGenerateReport} disabled={loadingReport}>
               <div className="absolute inset-0 bg-gradient-to-r from-indigo-600 to-purple-600 transition-transform duration-300 group-hover:scale-105"></div>
               <div className="relative flex items-center justify-center gap-2">
                 {loadingReport ? (<><Loader2 className="animate-spin w-4 h-4"/> Analyzing Market...</>) : (<><TrendingUp className="w-4 h-4"/> Generate Investment Strategy ✨</>)}
               </div>
            </Button>
            {aiReport && (
              <div className="relative group">
                <div className="absolute -inset-0.5 bg-gradient-to-r from-amber-500 to-purple-600 rounded-xl blur opacity-30 group-hover:opacity-50 transition duration-500"></div>
                <div className="relative bg-slate-900 p-6 rounded-xl border border-slate-700/50 backdrop-blur-xl animate-fade-in">
                  <div className="flex items-center justify-between mb-4 pb-4 border-b border-slate-700/50">
                    <div className="flex items-center gap-2 text-amber-400 font-bold"><Lightbulb className="w-5 h-5" /><span>Acrely AI Strategy</span></div>
                    <div className="flex gap-2">
                      <button onClick={handleGenerateReport} className="p-2 hover:bg-white/10 rounded-lg transition-colors text-slate-400 hover:text-white" title="Regenerate"><RefreshCw className="w-4 h-4" /></button>
                      <button onClick={handleCopy} className="p-2 hover:bg-white/10 rounded-lg transition-colors text-slate-400 hover:text-white" title="Copy">{copied ? <CheckCircle2 className="w-4 h-4 text-emerald-400" /> : <Copy className="w-4 h-4" />}</button>
                    </div>
                  </div>
                  <div className="prose prose-invert max-w-none">{formatText(aiReport)}</div>
                  <div className="mt-6 pt-4 border-t border-slate-700/50 flex justify-end"><button className="text-xs text-indigo-400 hover:text-indigo-300 flex items-center gap-1 transition-colors">Share this analysis <Share2 className="w-3 h-3" /></button></div>
                </div>
              </div>
            )}
          </div>
        </div>
        <div className="space-y-6">
          {[{ title: "High-Yield Assets", desc: "Curated Grade-A commercial properties in IT hubs." }, { title: "Fully Managed", desc: "We handle tenants, maintenance, and legal compliance." }, { title: "Liquidity", desc: "Sell your shares anytime on our secondary marketplace." }].map((item, idx) => (
