const App = () => {
  const [view, setView] = useState('home');
  const [selectedProperty, setSelectedProperty] = useState(null);
  const [isScrolled, setIsScrolled] = useState(false);
  const [properties, setProperties] = useState([]);
  const [agents, setAgents] = useState([]);
  const [user, setUser] = useState(null);

  // ---- FIREBASE INIT & DATA SYNC ---- //
  useEffect(() => {
    // 1. Authenticate (Anonymous)
    const initAuth = async () => {
      try {
        if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) {
          await signInWithCustomToken(auth, __initial_auth_token);
        } else {
          await signInAnonymously(auth);
        }
      } catch (error) {
        console.error("Auth failed:", error);
      }
    };
    initAuth();

    const unsubscribeAuth = onAuthStateChanged(auth, setUser);
    return () => unsubscribeAuth();
  }, []);

  // 2. Fetch Data (Real-time)
  useEffect(() => {
    if (!user) return; // Wait for auth

    // Properties Listener
    const propsRef = collection(db, 'artifacts', appId, 'public', 'data', 'properties');
    const unsubProps = onSnapshot(propsRef, (snapshot) => {
        const fetchedProps = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        if (fetchedProps.length === 0) {
            // Seed DB if empty
            INITIAL_PROPERTIES.forEach(p => {
               addDoc(propsRef, p); 
            });
        } else {
            setProperties(fetchedProps);
        }
    }, (err) => console.error("Props Error:", err));

    // Agents Listener
    const agentsRef = collection(db, 'artifacts', appId, 'public', 'data', 'agents');
    const unsubAgents = onSnapshot(agentsRef, (snapshot) => {
        const fetchedAgents = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        if (fetchedAgents.length === 0) {
            // Seed DB
            INITIAL_AGENTS.forEach(a => {
                addDoc(agentsRef, a);
            });
        } else {
            setAgents(fetchedAgents);
        }
    }, (err) => console.error("Agents Error:", err));

    return () => {
        unsubProps();
        unsubAgents();
    };
  }, [user]);

  // ---- Handlers ---- //
  useEffect(() => {
    const handleScroll = () => {
      const scrolled = window.scrollY > 50;
      if (scrolled !== isScrolled) {
        setIsScrolled(scrolled);
      }
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, [isScrolled]);

  const handlePropertyClick = useCallback((property) => {
    setSelectedProperty(property);
  }, []);

  const handleCloseModal = useCallback(() => {
    setSelectedProperty(null);
  }, []);

  const handleSetView = useCallback((newView) => {
    setView(newView);
    window.scrollTo(0, 0);
  }, []);

  return (
    <div className="font-sans text-slate-900 bg-white min-h-screen relative">
      {view !== 'login' && view !== 'signup' && (
        <Navbar setView={handleSetView} view={view} isScrolled={isScrolled} />
      )}

      <main>
        {view === 'home' && (
          <>
            <Hero setView={handleSetView} />
            <div className="py-24 container mx-auto px-4 md:px-6">
              <div className="flex justify-between items-end mb-10">
                <div>
                   <h2 className="text-3xl md:text-4xl font-bold mb-2 text-slate-900">Trending Homes</h2>
                   <p className="text-slate-500 text-lg">Curated properties popular in your city this week.</p>
                </div>
                <Button variant="ghost" onClick={() => handleSetView('buy')} className="hidden md:flex">View All <ArrowRight className="w-4 h-4" /></Button>
              </div>

              <div className="flex flex-col lg:flex-row gap-8">
                {/* Cards Column */}
                <div className="lg:w-2/3 grid grid-cols-1 md:grid-cols-2 gap-6">
                  {properties.slice(0, 4).map(p => ( 
                    <PropertyCard key={p.id} property={p} onClick={handlePropertyClick} />
                  ))}
                </div>

                {/* Map Column */}
                <div className="lg:w-1/3 bg-slate-100 rounded-2xl overflow-hidden min-h-[400px] relative border border-slate-200 shadow-inner group">
                   <div className="absolute inset-0 opacity-40" style={{backgroundImage: 'radial-gradient(#94a3b8 2px, transparent 2px)', backgroundSize: '24px 24px'}}></div>
                   <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center">
                      <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-lg mb-4 text-amber-500 animate-bounce">
                        <MapPin className="w-8 h-8" />
                      </div>
                      <h3 className="text-xl font-bold text-slate-700 mb-2">Explore on Map</h3>
                      <p className="text-slate-500 text-sm mb-6">See where these trending properties are located relative to you.</p>
                      <Button onClick={() => handleSetView('buy')}>View Interactive Map</Button>
                   </div>
                </div>
              </div>

              <div className="mt-20 bg-slate-900 rounded-3xl p-8 md:p-16 relative overflow-hidden flex flex-col md:flex-row items-center justify-between gap-12 shadow-2xl">
                 <div className="relative z-10 max-w-xl">
                   <h3 className="text-2xl md:text-4xl font-bold text-white mb-6 leading-tight">Sell with confidence.</h3>
                   <p className="text-slate-300 mb-8 text-base md:text-lg">Get a verified buyer for your home in 45 days or less. No hidden fees, just results.</p>
                   <Button variant="secondary" onClick={() => handleSetView('sell')} className="text-lg px-8 py-4 w-full md:w-auto">List Your Property</Button>
                 </div>
                 <div className="relative z-10 hidden md:block">
                   <ShieldCheck className="w-48 h-48 text-slate-800" />
                 </div>
                 <div className="absolute top-0 right-0 w-64 h-64 bg-amber-500/10 rounded-full blur-3xl transform translate-x-1/2 -translate-y-1/2"></div>
                 <div className="absolute bottom-0 left-0 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl transform -translate-x-1/2 translate-y-1/2"></div>
              </div>
            </div>
          </>
        )}

        {view === 'buy' && (
          <ListingPage properties={properties} onPropertyClick={handlePropertyClick} />
        )}

        {view === 'sell' && <SellerPage />}

        {view === 'invest' && <InvestSection />}

        {view === 'agents' && <AgentsPage />}

        {view === 'about' && <AboutPage />}

        {view === 'careers' && <CareersPage />}

        {(view === 'login' || view === 'signup') && <AuthPage mode={view} setView={handleSetView} />}
      </main>

      {/* Global AI Chat Component */}
      <AcrelyAIChat properties={properties} agents={agents} />

      {view !== 'login' && view !== 'signup' && <Footer setView={handleSetView} />}

      {selectedProperty && (
        <PropertyDetailModal property={selectedProperty} onClose={handleCloseModal} />
      )}
    </div>
  );
};

export default App; 

